<?php
require '../../config/config.php';
$items = mysqli_query($conn, "SELECT t.*, ts.name AS status_name, ts.color AS status_color, tp.name AS priority_name FROM tickets t LEFT JOIN ticket_statuses ts ON ts.id=t.status_id LEFT JOIN ticket_priorities tp ON tp.id=t.priority_id WHERE t.company_id=$company_id ORDER BY t.id DESC");
?>
<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Tickets</title><link rel="stylesheet" href="../../css/styles.css"></head><body><div class="container"><?php include '../../includes/sidebar.php'; ?><div class="main-content"><?php include '../../includes/header.php'; ?><div class="content"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:20px;"><h1>🎫 Tickets</h1><a class="btn btn-primary" href="create.php">+ Create Ticket</a></div><div class="card"><table><thead><tr><th>ID</th><th>Code</th><th>Title</th><th>Status</th><th>Priority</th><th>Created</th><th>Actions</th></tr></thead><tbody><?php if($items && mysqli_num_rows($items)): while($t=mysqli_fetch_assoc($items)): ?><tr><td><?php echo (int)$t['id']; ?></td><td><?php echo sanitize($t['ticket_code']??'-'); ?></td><td><?php echo sanitize($t['title']); ?></td><td><span class="badge" style="background-color:<?php echo sanitize($t['status_color']?:'#9aa4b2'); ?>33;color:<?php echo sanitize($t['status_color']?:'#9aa4b2'); ?>;"><?php echo sanitize($t['status_name']?:'Open'); ?></span></td><td><?php echo sanitize($t['priority_name']?:'-'); ?></td><td><?php echo sanitize($t['created_at']); ?></td><td><a class="btn btn-sm" href="create.php?id=<?php echo (int)$t['id']; ?>">Edit</a> <a class="btn btn-sm btn-danger" href="delete.php?id=<?php echo (int)$t['id']; ?>" onclick="return confirm('Delete ticket?');">Delete</a></td></tr><?php endwhile; else: ?><tr><td colspan="7" style="text-align:center;">No tickets found.</td></tr><?php endif; ?></tbody></table></div></div></div></div><script src="../../js/theme.js"></script></body></html>
